export type TranslationKey = keyof typeof de;
const dictionaries = { de, en } as const;
const STORAGE_KEY = 'flowz:locale';
let locale: Locale = readLocale();
const listeners = new Set<() => void>();
export const subscribeLocale=(listener:()=>void)=>{listeners.add(listener);return()=>listeners.delete(listener);};

function readLocale(): Locale {
  if (typeof localStorage === 'undefined') return 'de';
  try{return localStorage.getItem(STORAGE_KEY) === 'en' ? 'en' : 'de';}catch{return 'de';}
}

function interpolate(message: string, vars: Vars): string {
  const plural = /\{(\w+),\s*plural,\s*one\s*\{([^{}]*)\}\s*other\s*\{([^{}]*)\}\}/g;
  return message.replace(plural, (_, name: string, one: string, other: string) => {
    const count = Number(vars[name] ?? 0);
    return (count === 1 ? one : other).replaceAll('#', formatNumber(count));
  }).replace(/\{(\w+)\}/g, (_, name: string) => String(vars[name] ?? `{${name}}`));
}

export function getLocale(): Locale { return locale; }
export function setLocale(next: Locale): void {
  if (locale === next) return;
  locale = next;
  try { localStorage.setItem(STORAGE_KEY, next); } catch { /* Storage may be unavailable. */ }
  if (typeof document !== 'undefined') document.documentElement.lang = next;
  listeners.forEach((listener) => listener());
}
export function t(key: TranslationKey, vars: Vars = {}): string { return interpolate(dictionaries[locale][key] ?? de[key], vars); }
export function useI18n() {
  const active = useSyncExternalStore(subscribeLocale, getLocale, getLocale);
  return { locale: active, setLocale, t: (key: TranslationKey, vars?: Vars) => interpolate(dictionaries[active][key] ?? de[key], vars ?? {}) };
}

export function initializeLocale(): void { if (typeof document !== 'undefined') document.documentElement.lang = locale; }
export function formatNumber(value: number, options?: Intl.NumberFormatOptions): string { return new Intl.NumberFormat(locale, options).format(value); }
export function formatCurrency(value: number, currency = 'USD'): string { return new Intl.NumberFormat(locale, { style: 'currency', currency, maximumFractionDigits: 6 }).format(value); }
export function formatDate(value: string | number | Date, options: Intl.DateTimeFormatOptions = { dateStyle: 'medium', timeStyle: 'short' }): string { return new Intl.DateTimeFormat(locale, options).format(new Date(value)); }
export function formatDuration(seconds: number): string { if (seconds < 60) return new Intl.NumberFormat(locale, { maximumFractionDigits: 1 }).format(seconds) + (locale === 'de' ? ' s' : ' sec'); const minutes = Math.floor(seconds / 60); const rest = Math.round(seconds % 60); return locale === 'de' ? `${minutes} Min. ${rest} Sek.` : `${minutes} min ${rest} sec`; }
export function formatFileSize(bytes: number): string { const units = ['B','KB','MB','GB','TB']; let value = Math.max(0, bytes); let index = 0; while (value >= 1024 && index < units.length - 1) { value /= 1024; index += 1; } return `${formatNumber(value, { maximumFractionDigits: index ? 1 : 0 })} ${units[index]}`; }
export type AppErrorCode='project_unknown'|'cancelled'|'cancel_requested'|'paid_submit_unknown'|'paid_run_in_flight'|'validation_failed'|'disk_error'|'project_changed'|'empty_result'|'api_key_missing'|'invalid_response'|'operation_failed';
export type AppError={source:'app';code:AppErrorCode;detail?:string}|{source:'provider';provider:string;detail:string};
const APP_ERRORS:Record<Locale,Record<AppErrorCode,string>>={de:{project_unknown:'Unbekannter Projektfehler',cancelled:'Vor dem Senden abgebrochen.',cancel_requested:'Abbruch angefordert. Falls der Provider den Lauf bereits angenommen hat, sichert FlowZ ein späteres Ergebnis weiterhin.',paid_submit_unknown:'Der bezahlte Request kann bereits angenommen worden sein. FlowZ sendet ihn nicht automatisch erneut.',paid_run_in_flight:'Für diese Node läuft bereits eine bezahlte Ausführung.',validation_failed:'Bitte prüfe die Eingaben.',disk_error:'Lokales Speichern ist fehlgeschlagen.',project_changed:'Das Projekt wurde während des Vorgangs gewechselt.',empty_result:'Es wurde kein Ergebnis zurückgegeben.',api_key_missing:'Der API-Key fehlt.',invalid_response:'Die Antwort ist ungültig.',operation_failed:'Der Vorgang konnte nicht abgeschlossen werden.'},en:{project_unknown:'Unknown project error',cancelled:'Cancelled before submission.',cancel_requested:'Cancellation requested. If the provider already accepted the run, FlowZ will still preserve a later result.',paid_submit_unknown:'The paid request may already have been accepted. FlowZ will not submit it automatically again.',paid_run_in_flight:'A paid run is already active for this node.',validation_failed:'Check the inputs.',disk_error:'Local storage failed.',project_changed:'The project changed during the operation.',empty_result:'No result was returned.',api_key_missing:'The API key is missing.',invalid_response:'The response is invalid.',operation_failed:'The operation could not be completed.'}};
export const appError=(code:AppErrorCode,detail?:string):AppError=>({source:'app',code,...(detail?{detail}:{})});
export const providerError=(provider:string,detail:string):AppError=>({source:'provider',provider,detail});
const APP_ERROR_PREFIX='FLOWZ_APP_ERROR:';
export const isSerializedAppError=(value:string):boolean=>value.startsWith(APP_ERROR_PREFIX);
export const serializeAppError=(error:AppError):string=>`${APP_ERROR_PREFIX}${JSON.stringify(error)}`;
export const appErrorMessage=(code:AppErrorCode,detail?:string):string=>serializeAppError(appError(code,detail));
export const providerErrorMessage=(provider:string,detail:string):string=>serializeAppError(providerError(provider,detail));
function safeExternalDetail(value:unknown):string{const text=String(value??'').replace(/\b[a-z][a-z0-9+.-]*:\/\/\S+/gi,'[URL]').replace(/\b(?:sk-(?:or-v1-)?[A-Za-z0-9_-]{16,}|BSA[A-Za-z0-9_-]{12,}|[A-Fa-f0-9-]{24,}:[A-Za-z0-9_-]{16,}|Bearer\s+\S+)\b/gi,'[REDACTED]').replace(/[\u0000-\u001f\u007f]/g,' ').trim();return text.slice(0,500);}
function parsedAppError(value:unknown):AppError|undefined{if(value&&typeof value==='object'&&'source'in value)return value as AppError;const raw=value instanceof Error?value.message:typeof value==='string'?value:'';if(!raw.startsWith(APP_ERROR_PREFIX))return;try{const parsed=JSON.parse(raw.slice(APP_ERROR_PREFIX.length)) as Partial<AppError>;if(parsed.source==='app'&&typeof parsed.code==='string'&&parsed.code in APP_ERRORS.de)return parsed as AppError;if(parsed.source==='provider'&&typeof parsed.provider==='string'&&typeof parsed.detail==='string')return parsed as AppError;}catch{}return;}
export function localizeErrorMessage(value: unknown): string {
  const typed=parsedAppError(value);if(typed){if(typed.source==='provider')return `${safeExternalDetail(typed.provider)}: ${safeExternalDetail(typed.detail)}`;const base=APP_ERRORS[locale][typed.code]??APP_ERRORS[locale].operation_failed;const detail=safeExternalDetail(typed.detail);return detail?`${base} ${detail}`:base;}
  const message=value instanceof Error?value.message:String(value);
  const provider=/\b(?:fal\.ai|OpenRouter|Brave|Provider|HTTP|API|quota|rate.?limit|429|402|401|400)\b/i.test(message);
  return provider?`${locale==='de'?'Provider-Antwort':'Provider response'}: ${safeExternalDetail(message)}`:APP_ERRORS[locale].operation_failed;
}

