export function localizeLegacyLabel(value: string): string { if(locale!=='en')return value;const direct=legacyEnglish.get(value);if(direct)return direct;const numbered=value.match(/^(\d+\s*·\s*)(.+)$/);return numbered&&legacyEnglish.has(numbered[2])?`${numbered[1]}${legacyEnglish.get(numbered[2])}`:value; }


