export function localizeTemplateMeta(template:CanvasTemplate):CanvasTemplate { const translated=locale==='en'?templateEnglish[template.id]:undefined;if(!translated)return template;return{...template,name:translated.name,summary:translated.summary,firstRun:translated.firstRun,hints:translated.hints,nodes:template.nodes.map(node=>({...node,...(translated.labels[node.id]?{label:translated.labels[node.id]}:{})})),groups:template.groups.map(group=>({...group,name:translated.group.name,description:translated.group.description}))}; }
export function localizedTemplateNodeLabel(labelId:string,fallback:string):string{if(locale!=='en')return fallback;const match=labelId.match(/^template:([a-z0-9-]+):([a-zA-Z0-9-]+)$/);return match?templateEnglish[match[1]]?.labels[match[2]]??fallback:fallback;}

